CREATE TABLE HNM_メニュー情報(     会社コード                  CHAR(2)            NOT NULL,    現行メニュー連携フラグ      CHAR(1)            NOT NULL,    メニューＩＤ                VARCHAR2(40)       NOT NULL,    有効開始日                  DATE               NOT NULL,    有効終了日                  DATE               NOT NULL,    メニュー単位連番            CHAR(6)            NOT NULL,    メニュー名                  VARCHAR2(40)       NOT NULL,    メニュー単位名              VARCHAR2(40)       NOT NULL,    起動ＵＲＬ                  VARCHAR2(200),    サービス区分                CHAR(2)            NOT NULL,    更新系区分                  CHAR(1)            NOT NULL,    異動後サービス許可日数      NUMBER(3)          NOT NULL,    標準サービス開始時間        CHAR(4)            NOT NULL,    標準サービス終了時間        CHAR(4)            NOT NULL,    サービス開始変更時間        CHAR(4),    サービス終了変更時間        CHAR(4),    最早サービス時間            CHAR(4)            NOT NULL,    最遅サービス時間            CHAR(4)            NOT NULL,    月曜サービス開始時間        CHAR(4),    月曜サービス終了時間        CHAR(4),    火曜サービス開始時間        CHAR(4),    火曜サービス終了時間        CHAR(4),    水曜サービス開始時間        CHAR(4),    水曜サービス終了時間        CHAR(4),    木曜サービス開始時間        CHAR(4),    木曜サービス終了時間        CHAR(4),    金曜サービス開始時間        CHAR(4),    金曜サービス終了時間        CHAR(4),    土曜サービス開始時間        CHAR(4),    土曜サービス終了時間        CHAR(4),    日曜サービス開始時間        CHAR(4),    日曜サービス終了時間        CHAR(4),    備考１                      VARCHAR2(100),    備考２                      VARCHAR2(100),    備考３                      VARCHAR2(100),    登録日時                    DATE,     登録者氏名コード            VARCHAR2(7),     最終更新日時                DATE,     最終更新者ＩＤ              VARCHAR2(15),     有効フラグ                  CHAR(1),     削除フラグ                  CHAR(1),    CONSTRAINT HNM001_PK PRIMARY KEY(会社コード, 現行メニュー連携フラグ, メニューＩＤ, 有効開始日)         USING INDEX NOLOGGING PCTFREE 10 INITRANS 2 MAXTRANS 255             TABLESPACE USERTBS1             STORAGE(INITIAL 1M NEXT 1M MINEXTENTS 1 MAXEXTENTS UNLIMITED PCTINCREASE 5                  FREELISTS 1 FREELIST GROUPS 1 BUFFER_POOL DEFAULT ) )